import{c as t,Q as e,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"What Matters For Safety Alignment?","description":"","frontmatter":{"title":"What Matters For Safety Alignment?","arxiv_id":2601.03868,"authors":"Xing Li, Hui-Ling Zhen, Lihao Yin, et al.","published":"2026-01-07T00:00:00.000Z","source":"https://arxiv.org/abs/2601.03868","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-01-07-what-matters-safety-alignment-2601-03868.md","filePath":"research/papers/2026-01-07-what-matters-safety-alignment-2601-03868.md","lastUpdated":1779901665000}'),i={name:"research/papers/2026-01-07-what-matters-safety-alignment-2601-03868.md"};function o(s,a,l,h,d,p){return e(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="what-matters-for-safety-alignment" tabindex="-1">What Matters For Safety Alignment? <a class="header-anchor" href="#what-matters-for-safety-alignment" aria-label="Permalink to &quot;What Matters For Safety Alignment?&quot;">​</a></h1><p><strong>ArXiv</strong>: 2601.03868 | <strong>Date</strong>: 2026-01-07 (修訂 2026-02-24) | <strong>Authors</strong>: Xing Li, Hui-Ling Zhen, Lihao Yin, et al. | <strong>Category</strong>: cs.CL</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>大規模實證研究，評估 32 個模型（13 個系列，3B–235B 參數）的安全對齊能力，涵蓋 6 個關鍵模型特性、3 種外部攻擊技術、5 個安全資料集、56 種越獄技術、4 種思維鏈攻擊策略，共 <strong>460 萬次 API 調用</strong>。</p><h2 id="主要發現" tabindex="-1">主要發現 <a class="header-anchor" href="#主要發現" aria-label="Permalink to &quot;主要發現&quot;">​</a></h2><h3 id="最安全的模型" tabindex="-1">最安全的模型 <a class="header-anchor" href="#最安全的模型" aria-label="Permalink to &quot;最安全的模型&quot;">​</a></h3><p>GPT-OSS-20B、Qwen3-Next-80B-A3B-Thinking、GPT-OSS-120B — 共同特點：整合推理和自我反思機制。</p><h3 id="post-training-風險" tabindex="-1">Post-Training 風險 <a class="header-anchor" href="#post-training-風險" aria-label="Permalink to &quot;Post-Training 風險&quot;">​</a></h3><p><strong>關鍵發現</strong>：後訓練（post-training）和知識蒸餾（knowledge distillation）可能導致「安全對齊的系統性退化」。安全應在此階段作為<strong>顯式約束</strong>，而非事後考量。</p><h3 id="chain-of-thought-脆弱性" tabindex="-1">Chain-of-Thought 脆弱性 <a class="header-anchor" href="#chain-of-thought-脆弱性" aria-label="Permalink to &quot;Chain-of-Thought 脆弱性&quot;">​</a></h3><table tabindex="0"><thead><tr><th>攻擊方式</th><th>攻擊成功率</th></tr></thead><tbody><tr><td>CoT 攻擊（通過 response prefix）</td><td>平均 <strong>3.34× 提升</strong></td></tr><tr><td>部分模型極端案例</td><td>從 <strong>0.6% → 96.3%</strong></td></tr></tbody></table><p>文字補全介面（text-completion interfaces）和用戶定義 response prefix 存在嚴重安全風險。</p><h3 id="主要攻擊方法" tabindex="-1">主要攻擊方法 <a class="header-anchor" href="#主要攻擊方法" aria-label="Permalink to &quot;主要攻擊方法&quot;">​</a></h3><ul><li>角色扮演（Roleplay）</li><li>提示注入（Prompt Injection）</li><li>梯度搜索對抗提示（Gradient-based adversarial prompts）</li></ul><h2 id="模型參數大小-vs-安全性" tabindex="-1">模型參數大小 vs 安全性 <a class="header-anchor" href="#模型參數大小-vs-安全性" aria-label="Permalink to &quot;模型參數大小 vs 安全性&quot;">​</a></h2><p>規模效應並非線性：</p><ul><li>最安全模型包括 20B 和 80B（非最大的 235B）</li><li>整合推理機制（thinking）比純粹規模更重要</li></ul><h2 id="對-workspace-的意義" tabindex="-1">對 Workspace 的意義 <a class="header-anchor" href="#對-workspace-的意義" aria-label="Permalink to &quot;對 Workspace 的意義&quot;">​</a></h2><p>與 <code>2026-05-23-cheating-agents-benchmark-manipulation</code> 形成互補：</p><ul><li>前者：benchmark manipulation（外部攻擊評估系統）</li><li>本文：safety alignment failure（模型在安全場景中的失敗）</li></ul><p>CoT 攻擊脆弱性提示：在 agentic 環境中使用 response prefix 引導時需特別注意安全邊界。</p><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Safety &amp; Alignment</strong> — 迄今最大規模的安全對齊系統評估，CoT 3.34× 攻擊放大效應是 agentic 環境安全設計的關鍵警示。</p>',23)])])}const m=t(i,[["render",o]]);export{g as __pageData,m as default};
